**C++ 模板（回溯框架）**：

```cpp
// 回溯框架（子集型：選或不選）
vector<vector<int>> result;
vector<int> path;
void backtrack(vector<int>& nums, int i) {
    if (i == (int)nums.size()) {
        result.push_back(path);
        return;
    }
    // 不選 nums[i]
    backtrack(nums, i + 1);
    // 選 nums[i]
    path.push_back(nums[i]);
    backtrack(nums, i + 1);
    path.pop_back(); // 回溯
}
```

